package be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfa.bijdrage.patronaal;

import be.schaubroeck.lpb.rkm.rekenmotor.LoonElement;
import be.schaubroeck.lpb.rkm.rekenmotor.SleutelGegevens;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.MoneyKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBasisRszKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenPatronaalPriveRszKey;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfa.bijdrage.AbstractBijdrageMetPercentageBase;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.rkm.rekenresultaat.service.util.RekenresultaatBedrag;
import be.schaubroeck.lpb.tools.MaandTotaal3;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.enumtypes.Regulkode;
import be.schaubroeck.lpb.tools.service.RszConstantService;
import lombok.extern.slf4j.Slf4j;
import org.joda.time.LocalDate;

import java.math.BigDecimal;

@Slf4j
public class VerbrekingsvergoedingenSluitingsfonds extends AbstractBijdrageMetPercentageBase {
    public static final MoneyKey MONEY_KEY_INHOUDING = RekenPatronaalPriveRszKey.PATRONALE_BIJDRAGE_VERBREKINGSVERGOEDINGEN_SLUITINGSFONDS_KEY;

    public static final RekenresultaatBedrag REKENRESULTAAT_BEDRAG_BASIS = RekenresultaatBedrag.BASIS_VOB_NA_2014;
    public static final RekenresultaatBedrag REKENRESULTAAT_BEDRAG_INHOUDING = RekenresultaatBedrag.PATRONALE_BIJDRAGE_VERBREKINGSVERGOEDINGEN_SLUITINGSFONDS;

    public static final int GRENS1 = 44509;
    public static final int GRENS2 = 54509;
    public static final int GRENS3 = 64509;

    public static final BigDecimal PERCENTAGE_GRENS1 = BigDecimal.ONE;
    public static final BigDecimal PERCENTAGE_GRENS2 = BigDecimal.valueOf(2);
    public static final BigDecimal PERCENTAGE_GRENS3 = BigDecimal.valueOf(3);


    private final RegulManager regulManager;

    public VerbrekingsvergoedingenSluitingsfonds(RszConstantService rszConstantService, RegulManager regulManager) {
        super(rszConstantService);
        this.regulManager = regulManager;
    }

    @Override
    public BigDecimal getPercentage(SleutelGegevens gegevens, LocalDate zoekDatum) {
        if (isVerbrekingsvergoeding()) {
            BigDecimal jaarloon = getJaarloon(gegevens, zoekDatum);
            return getPercentage(jaarloon.intValue());
        } else {
            return BigDecimal.ZERO;
        }
    }

    BigDecimal getPercentage(int jaarloon) {
        if (jaarloon >= GRENS1 && jaarloon < GRENS2) {
            return PERCENTAGE_GRENS1;
        } else if (jaarloon >= GRENS2 && jaarloon < GRENS3) {
            return PERCENTAGE_GRENS2;
        } else if (jaarloon >= GRENS3) {
            return PERCENTAGE_GRENS3;
        } else {
            return BigDecimal.ZERO;
        }
    }

    public static boolean isVerbrekingsvergoeding() {
        // LPBUNI-28115 Nu steeds uitsluiten
        return false;
    }

    /*
      Het jaarloon wordt berekend op basis van de loon- en prestatiegegevens van het laatste kwartaal waarin prestaties werden geleverd
      waarvoor een loon verschuldigd was. De berekening gebeurt als volgt:
      * voor voltijdse werknemers: (A/B)* 260
      * voor deeltijdse werknemers: [(A/C)* D/5 ]*260

      Waarbij:
        A = bedrag van het brutoloon dat wordt aangegeven onder DmfA-looncode 1. Voor werknemers voor wie het vakantiegeld wordt uitbetaald door een vakantiekas wordt het bedrag vermenigvuldigd met 1,08.  (looncode is opgeslagen in de nieuwe kolom bezoldigingscode in de AKE)
          = bezoldigingscode = 1 in kode_ext_def
        B = aantal dagen aangegeven onder DmfA-prestatiecode 1
          prestkode = 1 (question)
          aantal dagen = "x" uit prestkalender
        C = aantal uren aangegeven onder prestatiecode 1
          aantal in de prestkalender
        D = aantal uren van de maatpersoon
          maatman in rszppo (question)
    */
    BigDecimal getJaarloon(SleutelGegevens gegevens, LocalDate zoekDatum) {
        BigDecimal bruto = getBruto(gegevens, zoekDatum);
        boolean isVoltijds = gegevens.getMaatman().compareTo(gegevens.getAanstelling()) == 0;
        if (isVoltijds) {
            return getVoltijdsJaarloon(gegevens, zoekDatum, bruto);
        } else {
            return getDeeltijdsJaarloon(gegevens, zoekDatum, bruto);
        }
    }

    BigDecimal getBruto(SleutelGegevens gegevens, LocalDate zoekDatum) {
        Opdracht opdracht = gegevens.getOpdracht();
        log.debug("VerbrekingsvergoedingenSluitingsfonds not implemented yet getBruto voor personeelsnr: {} opdrachtnr: {} en zoekDatum {}",
                opdracht.getPersoon().getPersoneelsNr(), opdracht.getOpdrachtnr(), zoekDatum);
        regulManager.doRegulException(opdracht, Regulkode.NIET_GEPROGRAMMEERD);
        return BigDecimal.ZERO;
    }

    BigDecimal getVoltijdsJaarloon(SleutelGegevens gegevens, LocalDate zoekDatum, BigDecimal bruto) {
        // aantalDagen
        // return (bruto / aantaldagen) * 260
        Opdracht opdracht = gegevens.getOpdracht();
        log.debug("VerbrekingsvergoedingenSluitingsfonds not implemented yet getVoltijdsPercentage voor personeelsnr: {} opdrachtnr: {}, zoekDatum {} en bruto {}",
                opdracht.getPersoon().getPersoneelsNr(), opdracht.getOpdrachtnr(), zoekDatum, bruto);
        regulManager.doRegulException(opdracht, Regulkode.NIET_GEPROGRAMMEERD);
        return BigDecimal.ZERO;
    }

    BigDecimal getDeeltijdsJaarloon(SleutelGegevens gegevens, LocalDate zoekDatum, BigDecimal bruto) {
        // aantalUren
        // return ((bruto / aantalUren) * gegevens.getMaatman() /5) * 260
        Opdracht opdracht = gegevens.getOpdracht();
        log.debug("VerbrekingsvergoedingenSluitingsfonds not implemented yet getDeeltijdsPercentage voor personeelsnr: {} opdrachtnr: {}, zoekDatum {} en bruto {}",
                opdracht.getPersoon().getPersoneelsNr(), opdracht.getOpdrachtnr(), zoekDatum, bruto);
        regulManager.doRegulException(opdracht, Regulkode.NIET_GEPROGRAMMEERD);
        return BigDecimal.ZERO;
    }

    public static void setOnLoonElement(LoonElement loonElement, Money bedrag) {
        if (isVerbrekingsvergoeding()) {
            loonElement.putProperty(RekenBasisRszKey.BASIS_VOB_NA_2014_KEY, bedrag);
        }
    }

    public static Money getBasisMaandTotaalBedrag(MaandTotaal3 mt3) {
        return mt3.getBasisVerbrekingsvergoedingenSluitingsfonds();
    }

    public static void setBasisMaandTotaalBedrag(MaandTotaal3 mt3, Money bedrag) {
        mt3.setBasisVerbrekingsvergoedingenSluitingsfonds(bedrag);
    }

    public static Money getInhoudingMaandTotaalBedrag(MaandTotaal3 mt3) {
        return mt3.getInhoudingVerbrekingsvergoedingenSluitingsfonds();
    }

    public static void setInhoudingMaandTotaalBedrag(MaandTotaal3 mt3, Money bedrag) {
        mt3.setInhoudingVerbrekingsvergoedingenSluitingsfonds(bedrag);
    }
}
